namespace sv_bd63f35024c9449e879e4d867cdd825b.Services;

public class WarehouseStateService
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId
    {
        get => _currentWarehouseId;
        set
        {
            if (_currentWarehouseId == value) return;
            _currentWarehouseId = value;
            NotifyStateChanged();
        }
    }

    public string CurrentWarehouseName =>
        Warehouses.TryGetValue(_currentWarehouseId, out var name) ? name : _currentWarehouseId;

    public static readonly Dictionary<string, string> Warehouses = new()
    {
        ["WH-001"] = "Warehouse A — Main Distribution",
        ["WH-002"] = "Warehouse B — East Regional",
        ["WH-003"] = "Warehouse C — West Regional",
        ["WH-004"] = "Warehouse D — Cold Storage",
    };

    public event Action? OnChange;

    private void NotifyStateChanged() => OnChange?.Invoke();
}

namespace sv_bd63f35024c9449e879e4d867cdd825b.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and coordinates
/// polling notifications across all subscribed components in a single circuit.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private int _lastLowStockCount;

    public int LastLowStockCount => _lastLowStockCount;

    /// <summary>
    /// Fired whenever new alert data arrives. All subscribed components
    /// receive this event, not just the one that triggered polling.
    /// </summary>
    public event Func<Task>? OnAlertDataChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query for items below minimum stock levels.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate latency-free DB call; return random 0–15.
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Registers a subscriber and starts polling if this is the first one.
    /// Call <see cref="Unsubscribe"/> when the component is disposed.
    /// </summary>
    public void Subscribe()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            StartPolling();
        }
    }

    /// <summary>
    /// Removes a subscriber and stops polling when none remain.
    /// </summary>
    public void Unsubscribe()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            StopPolling();
        }
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken cancellationToken)
    {
        // Fire immediately on start, then every 10 seconds.
        await FetchAndNotifyAsync();

        while (_timer is not null)
        {
            try
            {
                if (!await _timer.WaitForNextTickAsync(cancellationToken))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            await FetchAndNotifyAsync();
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        _lastLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);

        if (OnAlertDataChanged is not null)
        {
            await OnAlertDataChanged.Invoke();
        }
    }

    public void Dispose()
    {
        StopPolling();
    }
}

