@using sv_bd63f35024c9449e879e4d867cdd825b.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable
@rendermode InteractiveServer

<select class="form-select form-select-sm" style="width: 280px;"
        value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseStateService.Warehouses)
    {
        <option value="@wh.Key">@wh.Value</option>
    }
</select>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.CurrentWarehouseId = e.Value?.ToString() ?? "WH-001";
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_bd63f35024c9449e879e4d867cdd825b.Services
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

@if (AlertService.LastLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.LastLowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertDataChanged += OnAlertUpdated;
    }

    private async Task OnAlertUpdated()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= OnAlertUpdated;
    }
}

