@using sv_bd63f35024c9449e879e4d867cdd825b.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">
            <span class="bi bi-house-door-fill-nav-menu me-2" aria-hidden="true"></span>
            @WarehouseState.CurrentWarehouseName
        </h5>
        <p class="card-text text-muted">Selected warehouse: @WarehouseState.CurrentWarehouseId</p>
    </div>
</div>

<div class="card mb-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="display-4">
            @if (_lowStockCount > 0)
            {
                <span class="text-danger">@_lowStockCount</span>
            }
            else
            {
                <span class="text-success">0</span>
            }
        </p>
        <p class="text-muted">
            Items below minimum stock level &mdash; refreshes every 10 seconds.
        </p>
    </div>
</div>

@code {
    private int _lowStockCount;

    protected override void OnInitialized()
    {
        // Subscribe to alert polling (starts the timer if first subscriber).
        AlertService.Subscribe();
        AlertService.OnAlertDataChanged += OnAlertUpdated;

        // Re-fetch immediately when the warehouse changes mid-session.
        WarehouseState.OnChange += OnWarehouseChanged;
    }

    private async Task OnAlertUpdated()
    {
        _lowStockCount = AlertService.LastLowStockCount;
        await InvokeAsync(StateHasChanged);
    }

    private void OnWarehouseChanged()
    {
        // The next poll tick will automatically use the new warehouse ID.
        // Force an immediate re-render to update the heading/card.
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= OnAlertUpdated;
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.Unsubscribe();
    }
}

